315→async function loadWorkspaceSeeds(
316→  deps: ServerDependencies,
317→  workspaceRecord: RecordId<"workspace", string>,
318→  limit: number,
319→): Promise<OnboardingSeedItem[]> {
320→  const [edgeRows] = await deps.surreal
321→    .query<[ProvenanceEdgeRow[]]>(
322→      [
323→        "SELECT id, `in`, out, confidence, extracted_at",
324→        "FROM extraction_relation",
325→        "WHERE `in` IN array::concat(",
326→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
327→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
328→        ")",
329→        "ORDER BY extracted_at DESC",
330→        "LIMIT $limit;",
331→      ].join(" "),
332→      {
333→        workspace: workspaceRecord,
334→        limit,
335→      },
336→    )
337→    .collect<[ProvenanceEdgeRow[]]>();
338→
339→  const items: OnboardingSeedItem[] = [];
340→
341→  for (const edge of edgeRows) {
342→    const entityText = await readEntityText(deps.surreal, edge.out);
343→    if (!entityText) {
344→      continue;
345→    }
346→
347→    const sourceTable = edge.in.table.name;
348→    const entityTable = edge.out.table.name;
349→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
350→    const sourceLabel = await readSourceLabel(deps, edge.in);
351→
352→    items.push({
353→      id: edge.out.id as string,
354→      kind: entityTable as EntityKind,
355→      text: entityText,
356→      confidence: edge.confidence,
357→      sourceKind,
358→      sourceId: edge.in.id as string,
359→      ...(sourceLabel ? { sourceLabel } : {}),
360→    });
361→  }
362→
363→  return items;
364→}
365→
366→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
367→  const sourceTable = sourceRecord.table.name;
368→  if (sourceTable === "message") {
369→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
370→    if (!row) {
371→      return undefined;
372→    }
373→    return row.text.slice(0, 140);
374→  }
375→
376→  const chunk = await deps.surreal.select<{
377→    section_heading?: string;
378→    document: RecordId<"document", string>;
379→  }>(sourceRecord);
380→
381→  if (!chunk) {
382→    return undefined;
383→  }
384→
385→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
386→  if (!document) {
387→    return chunk.section_heading;
388→  }
389→
390→  if (chunk.section_heading) {
391→    return `${document.name} · ${chunk.section_heading}`;
392→  }
393→
394→  return document.name;
395→}
