315→
316→function base64url(buf: Buffer): string {
317→  return buf.toString("base64url");
318→}
319→
320→function generatePkce(): { verifier: string; challenge: string } {
321→  const verifier = base64url(randomBytes(32));
322→  const challenge = base64url(createHash("sha256").update(verifier).digest());
323→  return { verifier, challenge };
324→}
