326→/**
327→ * Obtain an OAuth2 JWT access token for MCP endpoints.
328→ * Requires a SurrealDB connection to skip consent screen.
329→ */
330→export async function getOAuthToken(
331→  baseUrl: string,
332→  surreal: Surreal,
333→  sessionHeaders: Record<string, string>,
334→  scopes: string = "graph:read graph:reason session:write offline_access",
335→): Promise<string> {
336→  // Trigger JWKS key generation if not yet done
337→  await fetch(`${baseUrl}/api/auth/jwks`);
338→
339→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
340→    method: "POST",
341→    headers: { "Content-Type": "application/json" },
342→    body: JSON.stringify({
343→      client_name: `test-client-${Date.now()}`,
344→      redirect_uris: ["http://127.0.0.1:9999/callback"],
345→      grant_types: ["authorization_code", "refresh_token"],
346→      response_types: ["code"],
347→      token_endpoint_auth_method: "none",
348→    }),
349→  });
350→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
351→
352→  const { client_id } = (await dcrRes.json()) as { client_id: string };
353→
354→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
355→    cid: client_id,
356→  });
357→
358→  const { verifier, challenge } = generatePkce();
359→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
360→  authUrl.searchParams.set("client_id", client_id);
361→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
362→  authUrl.searchParams.set("response_type", "code");
363→  authUrl.searchParams.set("scope", scopes);
364→  authUrl.searchParams.set("state", "test-state");
365→  authUrl.searchParams.set("code_challenge", challenge);
366→  authUrl.searchParams.set("code_challenge_method", "S256");
367→  authUrl.searchParams.set("resource", baseUrl);
368→
369→  const authRes = await fetch(authUrl.toString(), {
370→    headers: sessionHeaders,
371→    redirect: "manual",
372→  });
373→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
374→
375→  const location = authRes.headers.get("location")!;
376→  const redirectUrl = new URL(location, baseUrl);
377→  const code = redirectUrl.searchParams.get("code") ?? "";
378→  if (!code) throw new Error(`No code in redirect: ${location}`);
379→
380→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
381→    method: "POST",
382→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
383→    body: new URLSearchParams({
384→      grant_type: "authorization_code",
385→      code,
386→      redirect_uri: "http://127.0.0.1:9999/callback",
387→      client_id,
388→      code_verifier: verifier,
389→      resource: baseUrl,
390→    }),
391→  });
392→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
393→
394→  const tokens = (await tokenRes.json()) as { access_token: string };
395→  return tokens.access_token;
396→}
